import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import Container from "react-bootstrap/Container";
import NavbarBrand from "react-bootstrap/esm/NavbarBrand";
import Nav from "react-bootstrap/Nav";
import Navbar from "react-bootstrap/Navbar";
import NavDropdown from "react-bootstrap/NavDropdown";
import { useSelector } from "react-redux";

function CollapsibleExample() {
  const { cartTotalQuantity } = useSelector((state) => state.cart);
  // const [user, setUser] = useState("UserInfo")
  // console.log(JSON.stringify(user))
  const [name,setname]= useState()


  useEffect(()=>{
    var item_value = sessionStorage.getItem("UserInfo");

setname(item_value)

  },[])
  if (item_value) {
    return (
      <Navbar collapseOnSelect expand="lg" bg="dark" variant="dark">
        <Container>
          <NavbarBrand className="nav-bar">
            <a href="/home">
              <h2>Online Shoping</h2>
            </a>
          </NavbarBrand>
          <Navbar.Toggle aria-controls="responsive-navbar-nav" />
          <Navbar.Collapse id="responsive-navbar-nav">
            <Nav className="me-auto">
              <NavDropdown title="Dropdown" id="collasible-nav-dropdown">
                <NavDropdown.Item href="/mobile">Mobile</NavDropdown.Item>
                <NavDropdown.Item href="/tv">TV</NavDropdown.Item>
                <NavDropdown.Item href="/laptop">Laptop</NavDropdown.Item>
                <NavDropdown.Item href="/ac">AC</NavDropdown.Item>
                <NavDropdown.Item href="/watch">Watch</NavDropdown.Item>
              </NavDropdown>
            </Nav>

            <Nav>

              <Nav.Link href="/">Login {name}</Nav.Link>


              <Nav.Link href="/regi">Register</Nav.Link>
            </Nav>
            <Nav>
              <Link to="/cart">
                {" "}
                <div className="nav-bag">
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    width="35"
                    height="35"
                    fill="currentColor"
                    className="bi bi-handbag-fill"
                    viewBox="0 0 16 16"
                  >
                    <path d="M8 1a2 2 0 0 0-2 2v2H5V3a3 3 0 1 1 6 0v2h-1V3a2 2 0 0 0-2-2zM5 5H3.36a1.5 1.5 0 0 0-1.483 1.277L.85 13.13A2.5 2.5 0 0 0 3.322 16h9.355a2.5 2.5 0 0 0 2.473-2.87l-1.028-6.853A1.5 1.5 0 0 0 12.64 5H11v1.5a.5.5 0 0 1-1 0V5H6v1.5a.5.5 0 0 1-1 0V5z" />
                  </svg>

                  <span className="bag-quantity">
                    <span>{cartTotalQuantity}</span>
                  </span>
                </div>
              </Link>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>
    );
  }
  else{
    return (
      <Navbar collapseOnSelect expand="lg" bg="dark" variant="dark">
        <Container>
          <NavbarBrand className="nav-bar">
            <a href="/home">
              <h2>Online Shoping</h2>
            </a>
          </NavbarBrand>
          <Navbar.Toggle aria-controls="responsive-navbar-nav" />
          <Navbar.Collapse id="responsive-navbar-nav">
            <Nav className="me-auto">
              <NavDropdown title="Dropdown" id="collasible-nav-dropdown">
                <NavDropdown.Item href="/mobile">Mobile</NavDropdown.Item>
                <NavDropdown.Item href="/tv">TV</NavDropdown.Item>
                <NavDropdown.Item href="/laptop">Laptop</NavDropdown.Item>
                <NavDropdown.Item href="/ac">AC</NavDropdown.Item>
                <NavDropdown.Item href="/watch">Watch</NavDropdown.Item>
              </NavDropdown>
            </Nav>

            <Nav>

              <Nav.Link href="/">Login {name}</Nav.Link>


              <Nav.Link href="/regi">Register</Nav.Link>
            </Nav>
            <Nav>
              <Link to="/cart">
                {" "}
                <div className="nav-bag">
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    width="35"
                    height="35"
                    fill="currentColor"
                    className="bi bi-handbag-fill"
                    viewBox="0 0 16 16"
                  >
                    <path d="M8 1a2 2 0 0 0-2 2v2H5V3a3 3 0 1 1 6 0v2h-1V3a2 2 0 0 0-2-2zM5 5H3.36a1.5 1.5 0 0 0-1.483 1.277L.85 13.13A2.5 2.5 0 0 0 3.322 16h9.355a2.5 2.5 0 0 0 2.473-2.87l-1.028-6.853A1.5 1.5 0 0 0 12.64 5H11v1.5a.5.5 0 0 1-1 0V5H6v1.5a.5.5 0 0 1-1 0V5z" />
                  </svg>

                  <span className="bag-quantity">
                    <span>{cartTotalQuantity}</span>
                  </span>
                </div>
              </Link>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>
    );
  }
//   useEffect(() => {
    // localStorage.setItem('UserInfo', JSON.stringify(user)); //changed
//   }, [user]);
// console.log(user)
//   const userid = JSON.parse(localStorage.getItem('UserInfo')) //changed
//   console.log(userid)
  // const [resultsPerPage, setResultsPerPage] = useState();

}

export default CollapsibleExample;
